import numpy as np
from PIL import Image

try:
    import onnxruntime as ort  # pyodide 中可能不可用
except Exception:
    ort = None

image = Image.open("img_test.jpg").convert("RGB")
arr = np.array(image).astype("float32")
print("图片尺寸:", image.size, "数组形状:", arr.shape)

if ort is None:
    print("当前环境缺少 onnxruntime，已完成图片读取与预处理演示。")
else:
    print("onnxruntime 可用，可继续完成模型推理。")

